const LogAnalyzeModal = ({ onClose }) => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [activeCategory, setActiveCategory] = useState("사업/창업");
  const [selectedLogs, setSelectedLogs] = useState([]);
  const [selectedStyle, setSelectedStyle] = useState(null);
  const [progress, setProgress] = useState(0);

  const filteredLogs = PAST_LOGS.filter(log => log.category === activeCategory);

  useEffect(() => {
    if (step === 3) {
      setProgress(0);
      const interval = setInterval(() => {
        setProgress(prev => {
          if (prev >= 100) {
            clearInterval(interval);
            setTimeout(() => setStep(4), 300);
            return 100;
          }
          return prev + 2;
        });
      }, 40);
      return () => clearInterval(interval);
    }
  }, [step]);

  useEffect(() => {
    if (step === 4) {
      const timer = setTimeout(() => {
        navigate('/logs/result/my/detail');
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [step, navigate]);

  useEffect(() => {
    const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
    document.body.style.overflow = 'hidden';
    document.body.style.paddingRight = `${scrollbarWidth}px`;
    return () => {
      document.body.style.overflow = '';
      document.body.style.paddingRight = '';
    };
  }, []);

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget && step < 3) onClose();
  };

  const renderStep1 = () => (
    <>
      <S.CloseButtonWrapper>
        <S.CloseButton onClick={onClose}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M18 6L6 18M6 6L18 18" stroke="#A6A6A6" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </S.CloseButton>
      </S.CloseButtonWrapper>

      <S.TitleSection>
        <S.ModalTitle>과거의 비슷한 실패 기록</S.ModalTitle>
        <S.ModalSub>선택하시면 더 깊은 패턴을 찾을 수 있어요.</S.ModalSub>
      </S.TitleSection>

      <S.SectionRow>
        <S.SectionLabel>함께 분석할까요?</S.SectionLabel>
        <S.SelectedCount>{selectedLogs.length > 0 ? `${selectedLogs.length}개 선택됨` : ''}</S.SelectedCount>
      </S.SectionRow>

      <S.CategoryTabs>
        {CATEGORIES.map(cat => (
          <S.CategoryTab
            key={cat}
            $active={activeCategory === cat}
            onClick={() => setActiveCategory(cat)}
          >
            {cat}
          </S.CategoryTab>
        ))}
      </S.CategoryTabs>

      <S.LogList>
        {filteredLogs.length === 0 ? (
          <S.EmptyList>이 카테고리에는 로그가 없습니다.</S.EmptyList>
        ) : filteredLogs.map(log => {
          const isSelected = selectedLogs.some(l => l.id === log.id);
          return (
            <S.LogItem
              key={log.id}
              $selected={isSelected}
              onClick={() => {
                setSelectedLogs(prev =>
                  prev.some(l => l.id === log.id)
                    ? prev.filter(l => l.id !== log.id)
                    : [...prev, log]
                );
              }}
            >
              <S.LogItemContent>
                <S.LogItemCategory>{log.category}</S.LogItemCategory>
                <S.LogItemTitle>{log.title}</S.LogItemTitle>
                <S.LogItemDate>{log.date}</S.LogItemDate>
              </S.LogItemContent>
              <S.LogRadio $selected={isSelected}>
                {isSelected && (
                  <svg width="14" height="10" viewBox="0 0 14 10" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <path d="M1 5L5 9L13 1" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                )}
              </S.LogRadio>
            </S.LogItem>
          )
        })}
      </S.LogList>

      <S.BottomSection>
        <S.PrimaryButton onClick={() => setStep(2)}>
          {selectedLogs.length > 0 ? `${selectedLogs.length}개의 로그와 함께 분석하기` : '선택 없이 분석하기'}
        </S.PrimaryButton>
        <S.SkipLink onClick={() => setStep(2)}>건너뛰고 이번 로그만 분석 →</S.SkipLink>
      </S.BottomSection>
    </>
  );

  const renderStep2 = () => (
    <>
      <S.HeaderNav>
        <S.BackButton onClick={() => setStep(1)}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M19 12H5M5 12L12 19M5 12L12 5" stroke="#A6A6A6" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </S.BackButton>
        <S.CloseButton onClick={onClose}>
          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M18 6L6 18M6 6L18 18" stroke="#A6A6A6" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </S.CloseButton>
      </S.HeaderNav>

      <S.TitleSection>
        <S.ModalTitle>분석 스타일 설정</S.ModalTitle>
        <S.ModalSub>나에게 필요한 분석 스타일의 온도를 골라주세요.</S.ModalSub>
      </S.TitleSection>

      <S.StyleList>
        {ANALYSIS_STYLES.map(style => (
          <S.StyleCard
            key={style.id}
            $selected={selectedStyle === style.id}
            onClick={() => setSelectedStyle(style.id)}
          >
            <S.StyleIcon>{style.icon}</S.StyleIcon>
            <S.StyleContent>
              <S.StyleTitle>{style.title}</S.StyleTitle>
              <S.StyleDesc>{style.desc}</S.StyleDesc>
            </S.StyleContent>
            <S.StyleBadge $color={style.badgeColor} $bg={style.badgeBg}>
              {style.badge}
            </S.StyleBadge>
          </S.StyleCard>
        ))}
      </S.StyleList>

      <S.BottomSection>
        <S.PrimaryButton
          disabled={!selectedStyle}
          onClick={() => selectedStyle && setStep(3)}
        >
          선택한 스타일로 분석 시작
        </S.PrimaryButton>
      </S.BottomSection>
    </>
  );

  const renderStep3 = () => (
    <S.LoadingWrapper>
      <S.SpinnerRing />
      <S.LoadingTitle>
        입력하신 데이터를 기반으로<br />패턴을 분석하고 있어요
      </S.LoadingTitle>
      <S.LoadingSub>잠시만 기다려주세요...</S.LoadingSub>
      <S.ProgressBarWrapper>
        <S.ProgressBar $progress={progress} />
      </S.ProgressBarWrapper>
    </S.LoadingWrapper>
  );

  const renderStep4 = () => (
    <S.CompleteWrapper>
      <S.CompleteCircle>
        <S.CompleteCheck>✓</S.CompleteCheck>
      </S.CompleteCircle>
      <S.CompleteTitle>
        분석이 완료되어<br />정상 등록되었습니다.
      </S.CompleteTitle>
      <S.CompleteSub>결과 페이지로 이동합니다.</S.CompleteSub>
    </S.CompleteWrapper>
  );

  return (
    <S.Overlay onClick={handleOverlayClick}>
      <S.Modal $step={step}>
        {step === 1 && renderStep1()}
        {step === 2 && renderStep2()}
        {step === 3 && renderStep3()}
        {step === 4 && renderStep4()}
      </S.Modal>
    </S.Overlay>
  );
};

/* ─── Animations ─── */
const spin = keyframes`
  to { transform: rotate(360deg); }
`;

const progressAnim = keyframes`
  from { opacity: 0.6; }
  to { opacity: 1; }
`;

const fadeIn = keyframes`
  from { opacity: 0; transform: scale(0.9); }
  to { opacity: 1; transform: scale(1); }
`;

/* ─── Styled Components ─── */
const S = {};

S.Overlay = styled.div`
  position: fixed;
  inset: 0;
  background-color: rgba(0, 0, 0, 0.4);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
  overflow: hidden;
  animation: ${fadeIn} 0.2s ease;
`;

S.Modal = styled.div`
  width: 648px;
  height: 799px;
  background-color: ${theme.PALETTE.white};
  border-radius: 20px;
  padding: 40px 50px;
  position: relative;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.15);
  display: flex;
  flex-direction: column;
  border: 1px solid ${theme.GRAYSCALE[4]};
`;

S.HeaderNav = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
`;

S.ModalHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 4px;
`;

S.CloseButtonWrapper = styled.div`
  display: flex;
  justify-content: flex-end;
  margin-bottom: 8px;
`;

S.CloseButton = styled.button`
  background: none;
  border: none;
  cursor: pointer;
  padding: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: -10px;
`;

S.BackButton = styled.button`
  background: none;
  border: none;
  font-size: 20px;
  color: ${theme.GRAYSCALE[5]};
  cursor: pointer;
  padding: 4px;
  margin-left: -10px;
  &:hover { color: ${theme.TEXT_COLOR.basic}; }
`;

S.TitleSection = styled.div`
  margin-bottom: 40px;
`;

S.ModalTitle = styled.h2`
  font-size: ${theme.FONT_SIZE.h5};
  font-weight: ${theme.FONT_WEIGHT.bold};
  color: ${theme.TEXT_COLOR.basic};
`;

S.ModalSub = styled.p`
  font-size: ${theme.FONT_SIZE.h9};
  color: ${theme.GRAYSCALE[6]};
`;

S.SectionRow = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
`;

S.SectionLabel = styled.span`
  font-size: ${theme.FONT_SIZE.h8};
  font-weight: ${theme.FONT_WEIGHT.bold};
  color: ${theme.TEXT_COLOR.basic};
`;

S.SelectedCount = styled.span`
  font-size: ${theme.FONT_SIZE.h10};
  color: ${theme.PALETTE.third.main};
  font-weight: ${theme.FONT_WEIGHT.bold};
`;

S.CategoryTabs = styled.div`
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid ${theme.GRAYSCALE[2]};
`;

S.CategoryTab = styled.button`
  padding: 8px 20px;
  border-radius: 10px;
  font-size: ${theme.FONT_SIZE.h9};
  cursor: pointer;
  border: 1px solid ${({ $active }) => $active ? theme.PALETTE.third.main : theme.GRAYSCALE[3]};
  background-color: ${({ $active }) => $active ? theme.PALETTE.third.main : theme.PALETTE.white};
  color: ${({ $active }) => $active ? theme.PALETTE.white : theme.TEXT_COLOR.basic};
  font-weight: ${({ $active }) => $active ? theme.FONT_WEIGHT.bold : theme.FONT_WEIGHT.regular};
  transition: all 0.2s;
`;

S.LogList = styled.div`
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 16px;
  overflow-y: auto;
  padding-right: 8px;
  margin-bottom: 24px;

  &::-webkit-scrollbar {
    width: 6px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background-color: ${theme.GRAYSCALE[3]};
    border-radius: 10px;
  }
`;

S.EmptyList = styled.div`
  text-align: center;
  color: ${theme.GRAYSCALE[5]};
  font-size: ${theme.FONT_SIZE.h9};
  padding: 30px 0;
`;

